import{_ as t,o as a,c as r,ae as i}from"./chunks/framework.DrYEjkpc.js";const u=JSON.parse('{"title":"SkillRL","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillrl.md","filePath":"radar/tech-skillrl.md"}'),e={name:"radar/tech-skillrl.md"};function o(n,l,s,h,d,g){return a(),r("div",null,[...l[0]||(l[0]=[i('<h1 id="skillrl" tabindex="-1">SkillRL <a class="header-anchor" href="#skillrl" aria-label="Permalink to &quot;SkillRL&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 生成 / Skill 优化 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.53</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 通过经验蒸馏 + 自适应检索 + 递归共进化，让分层 SkillBank 与 RL 策略<strong>一起生长</strong>。<strong>+15.3% over baselines</strong>（ALFWorld / WebShop / 7 搜索增强任务）。</p><p><strong>来源</strong>:</p><ul><li>学术研究 - aiming-lab（多家合作）</li><li>论文 + 开源</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2602.08234" target="_blank" rel="noreferrer">arXiv 2602.08234</a></li><li>GitHub：<a href="https://github.com/aiming-lab/SkillRL" target="_blank" rel="noreferrer">aiming-lab/SkillRL</a></li><li>标题：<em>SkillRL: Evolving Agents via Recursive Skill-Augmented Reinforcement Learning</em></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="三个关键创新" tabindex="-1">三个关键创新 <a class="header-anchor" href="#三个关键创新" aria-label="Permalink to &quot;三个关键创新&quot;">​</a></h3><ol><li><strong>经验蒸馏机制</strong> — 把 Agent 的成功 / 失败经验提炼为分层 SkillBank（策略层 / 操作层）</li><li><strong>自适应检索策略</strong> — 同时支持通用启发式和任务特定的 Skill 召回</li><li><strong>递归共进化机制</strong> — Skill 库<strong>不是静态的</strong>，而是随 RL 策略一起更新；新策略发现的新模式被回写为 Skill，新 Skill 又改进下次策略</li></ol><h3 id="关键数字" tabindex="-1">关键数字 <a class="header-anchor" href="#关键数字" aria-label="Permalink to &quot;关键数字&quot;">​</a></h3><ul><li>在 <strong>ALFWorld、WebShop 和 7 个搜索增强任务</strong>上 <strong>outperforming strong baselines over +15.3%</strong></li></ul><h3 id="与-evoskill-的区别" tabindex="-1">与 EvoSkill 的区别 <a class="header-anchor" href="#与-evoskill-的区别" aria-label="Permalink to &quot;与 EvoSkill 的区别&quot;">​</a></h3><ul><li><strong>EvoSkill</strong>：纯 LLM-based，从失败中发现 Skill</li><li><strong>SkillRL</strong>：RL-based，Skill 库与 RL policy <strong>同时</strong>学习，强调&quot;共进化&quot;</li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>分层 SkillBank 构建</li><li>自适应 Skill 检索</li><li>与 RL 策略的递归共进化</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>需要可定义 reward 的环境，开放式任务受限</li><li>13 位作者均为学术研究，未见生产部署</li><li>RL 训练成本高于纯 LLM 路径</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.55</td><td>论文 + 开源实现</td></tr><tr><td>创新性</td><td>0.70</td><td>共进化机制是独有设计</td></tr><tr><td>落地程度</td><td>0.40</td><td>学术验证</td></tr><tr><td>生态活跃度</td><td>0.45</td><td>在 aiming-lab 生态内活跃</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.53</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2602.08234" target="_blank" rel="noreferrer">SkillRL 论文</a></li><li><a href="https://github.com/aiming-lab/SkillRL" target="_blank" rel="noreferrer">GitHub - aiming-lab/SkillRL</a></li></ul>',30)])])}const b=t(e,[["render",o]]);export{u as __pageData,b as default};
